    "PARAM_ANGLE_Y": { bone: "head", prop: "rot", mult: 0.5 },
    "PARAM_BODY_X": { bone: "body", prop: "rot", mult: 1 },
    "PARAM_ARM_L": { bone: "arm_l", prop: "rot", mult: 1 },
    "PARAM_ARM_R": { bone: "arm_r", prop: "rot", mult: -1 }
